mapper.select:
SELECT m.meetingId, m.title, m.placeName, m.meetingDate, m.startTime, m.maxMembers, m.status, m.content, m.thumbnailImage, s.name sportName, CONCAT(r.sido," ",r.sigungu," ",COALESCE(r.dong,"")) regionName, ( SELECT COUNT(*) FROM meetingParticipants mp WHERE mp.meetingId=m.meetingId AND mp.status="APPROVED" ) approvedCount FROM meetings m JOIN sports s ON m.sportId=s.sportId JOIN regions r ON m.regionId=r.regionId WHERE m.deletedAt IS NULL
AND s.name NOT IN
#{sport}
AND s.name = #{sportName}
AND m.meetingDate = #{meetingDate}
AND m.regionId=#{regionId}
AND m.status = #{status}
AND ( m.title LIKE CONCAT('%', #{keyword}, '%') OR m.content LIKE CONCAT('%', #{keyword}, '%')
OR s.name LIKE CONCAT('%', #{keyword}, '%')
OR r.sido LIKE CONCAT('%', #{keyword}, '%') OR r.sigungu LIKE CONCAT('%', #{keyword}, '%') OR r.dong LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY m.meetingDate ASC, m.startTime ASC

mapper.update:
UPDATE meetings
SET deletedAt = NOW()
WHERE meetingId = #{meetingId}

UPDATE meetings
SET status = #{status}
WHERE meetingId = #{meetingId}

mapper.select:
SELECT maxMembers
FROM meetings
WHERE meetingId = #{meetingId}
